defmodule MyApp.Accounts do
  use Supervisor
  
  def start_link(opts) do
    Supervisor.start_link(__MODULE__, opts)
  end
  
  def get_user!(id) do
    MyApp.Repo.get!(User, id)
  end
  
  def update_user(user, params) do
    user
